from datetime import date, timedelta
from dataclasses import dataclass

@dataclass
class BaselineWindow:
    start: date
    end: date
    excluded_periods: list[tuple[date, date]] = None   # holidays, incidents, migrations

    def __post_init__(self):
        if self.excluded_periods is None:
            self.excluded_periods = []

    @property
    def duration_weeks(self) -> float:
        return (self.end - self.start).days / 7

    @property
    def effective_days(self) -> int:
        """Business days in window minus excluded periods."""
        total = (self.end - self.start).days
        excluded = sum((e - s).days for s, e in (self.excluded_periods or []))
        return max(0, total - excluded)

    def includes_date(self, d: date) -> bool:
        if not (self.start <= d <= self.end):
            return False
        return not any(s <= d <= e for s, e in (self.excluded_periods or []))

    def validate(self, min_weeks: float = 4.0) -> list[str]:
        errors = []
        if self.duration_weeks < min_weeks:
            errors.append(
                f"Window is {self.duration_weeks:.1f} weeks; minimum is {min_weeks} weeks"
            )
        if self.effective_days < 20:
            errors.append(
                f"Only {self.effective_days} effective days after exclusions; "
                "sample may be insufficient"
            )
        return errors


# Example: 8-week window excluding a public holiday period
window = BaselineWindow(
    start=date(2025, 1, 6),
    end=date(2025, 2, 28),
    excluded_periods=[(date(2025, 1, 27), date(2025, 1, 27))],   # bank holiday
)
print(f"Window: {window.duration_weeks:.1f} weeks, {window.effective_days} effective days")
print("Validation:", window.validate() or "OK")
